--
-- Name: v_proyecto_resumen; Type: VIEW; Schema: notion_sync; Owner: ricardosoriagalvarro
--

CREATE VIEW notion_sync.v_proyecto_resumen AS
 SELECT p.notion_page_id AS proyecto_id,
    p.nombre AS proyecto_nombre,
    count(pp.producto_id) AS productos_total,
    sum(
        CASE
            WHEN (pr.estado = ANY (ARRAY['Listo'::text, 'Cerrado'::text])) THEN 1
            ELSE 0
        END) AS productos_cerrados
   FROM ((notion_sync.proyectos p
     LEFT JOIN notion_sync.proyecto_producto pp ON ((pp.proyecto_id = p.notion_page_id)))
     LEFT JOIN notion_sync.productos pr ON ((pr.notion_page_id = pp.producto_id)))
  GROUP BY p.notion_page_id, p.nombre;


ALTER VIEW notion_sync.v_proyecto_resumen OWNER TO ricardosoriagalvarro;

